{
  "mode": "All",
  "displayName": "Audit storage accounts without HTTPS-only traffic",
  "parameters": {
    "effect": {
      "type": "String",
      "defaultValue": "audit",
      "allowedValues": ["audit", "deny", "disabled"],
      "metadata": { "displayName": "Effect" }
    }
  },
  "policyRule": {
