# audit-policies.tf

resource "azurerm_policy_definition" "audit_https_storage" {
  name         = "audit-https-storage-accounts"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Audit storage accounts without HTTPS-only traffic"
  management_group_id = var.corp_mg_id

  policy_rule = jsonencode({
    if = {
      allOf = [
        { field = "type", equals = "Microsoft.Storage/storageAccounts" },
        { field = "Microsoft.Storage/storageAccounts/supportsHttpsTrafficOnly", notEquals = "true" }
      ]
    }
    then = {
      effect = "[parameters('effect')]"
    }
  })

  parameters = jsonencode({
    effect = {
      type         = "String"
      defaultValue = "audit"
      allowedValues = ["audit", "deny", "disabled"]
      metadata     = { displayName = "Effect" }
    }
  })
}

# Phase 1 assignment: audit only
resource "azurerm_management_group_policy_assignment" "audit_https_storage" {
  name                 = "audit-https-storage"
  display_name         = "Audit storage accounts without HTTPS-only traffic"
  policy_definition_id = azurerm_policy_definition.audit_https_storage.id
  management_group_id  = var.corp_mg_id

  # enforce = true means Default (evaluate and deny if effect=deny)
  # enforce = false means DoNotEnforce (evaluate but never deny, even if effect=deny)
  # Here we use enforce=true with effect=audit — evaluates and marks non-compliant but doesn't block
  enforce = true

  parameters = jsonencode({
    effect = { value = "audit" }
  })
}

# Phase 2 assignment (replace phase 1 after remediation):
# Change effect value to 'deny' in the parameters block above.
# No need to destroy and recreate the assignment — just update the parameter.

{
  "mode": "All",
  "displayName": "Audit VMs without Log Analytics agent",
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
        { "field": "Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType", "like": "Windows*" }
      ]
    },
    "then": {
      "effect": "auditIfNotExists",
      "details": {
        "type": "Microsoft.Compute/virtualMachines/extensions",
        "existenceCondition": {
          "allOf": [
            { "field": "Microsoft.Compute/virtualMachines/extensions/publisher", "equals": "Microsoft.EnterpriseCloud.Monitoring" },
            { "field": "Microsoft.Compute/virtualMachines/extensions/provisioningState", "equals": "Succeeded" }
          ]
        }
      }
    }
  }
}
